let raw = $input.first().json.output;
raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/, '').trim();
const evaluation = JSON.parse(raw);

// Carry forward the previous data
return [{
  json: {
    evaluation,
    tailoredResume: $('Resume Generator').item.json.output,
    retryCount: ($input.first().json.retryCount || 0)
  }
}];

const retryCount = ($json.retryCount || 0) + 1;

if (retryCount > 2) {
  return [
    {
      json: {
        tailoredResume: $json.tailoredResume,
        evaluation: $json.evaluation,
        forceProceed: true
      }
    }
  ];
}

return [
  {
    json: {
      retryCount,
      previousScore: $json.evaluation.total,
      feedback: ($json.evaluation.improvements || []).join('\n- '),
      missingKeywords: ($json.evaluation.missing_keywords || []).join(', ')
    }
  }
];

// Pull the binary data of the uploaded PDF
const binaryKey = '_resume_pdf';  // adjust if your form field name differs
const pdfBase64 = $('On form submission').item.binary[binaryKey].data;
const pdfBuffer = Buffer.from(pdfBase64, 'base64');

// Count "/Type /Page" occurrences in the PDF (lightweight, no dependencies)
const pdfText = pdfBuffer.toString('latin1');
const matches = pdfText.match(/\/Type\s*\/Page[^s]/g) || [];
let pageCount = matches.length;

// Fallback: try /Count entries
if (pageCount === 0) {
  const countMatch = pdfText.match(/\/Count\s+(\d+)/);
  if (countMatch) pageCount = parseInt(countMatch[1]);
}
if (pageCount === 0) pageCount = 1;  // safe default

// Pass forward both the extracted text AND the target page count
return [{
  json: {
    text: $('Extract from File').item.json.text,
    targetPageCount: pageCount
  }
}];
